import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - Next Generation", () => {
  it.todo("should return empty array when given empty array -- []");
  it.todo("should kill a single cell with 0 neighbors (Rule 1: underpopulation) -- [(0,0)] → []");
  it.todo("should kill two adjacent cells each with 1 neighbor (Rule 1: underpopulation) -- [(0,1),(1,1)] → []");
  it.todo("should keep alive a cell with exactly 2 neighbors (Rule 2: survival) -- center of horizontal 3 survives");
  it.todo("should keep alive a cell with exactly 3 neighbors (Rule 2: survival) -- block cells each have 3 neighbors");
  it.todo("should kill a cell with more than 3 neighbors (Rule 3: overpopulation) -- center of plus pattern with 4 neighbors dies");
  it.todo("should birth a dead cell with exactly 3 neighbors (Rule 4: reproduction) -- [(0,2),(1,2),(0,1)] → includes (1,1)");
  it.todo("should leave a block still life unchanged -- [(0,0),(1,0),(0,1),(1,1)] → same");
  it.todo("should oscillate a blinker from vertical to horizontal -- [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]");
  it.todo("should handle negative coordinates correctly -- cells at negative x/y");
});

type Cell = [number, number];

export function nextGeneration(cells: Cell[]): Cell[] {
  return [];
}

